package com.example.lessondesign.util; import io.jsonwebtoken.*; import java.util.Date; public class JwtUtil { private static final String SECRET = "cosmora-jwt-secret"; private static final long EXPIRATION = 86400000; public static String generateToken(String userId){ return Jwts.builder().setSubject(userId).setIssuedAt(new Date()).setExpiration(new Date(System.currentTimeMillis()+EXPIRATION)).signWith(SignatureAlgorithm.HS256,SECRET).compact(); } public static String getUserIdFromToken(String token){ return Jwts.parser().setSigningKey(SECRET).parseClaimsJws(token).getBody().getSubject(); } }